### 第 9 题【阅读程序】（2021 真题）以下代码中，输入的 n 等于 1001 时，程序不会发生下标越界。（ ）
```cpp
#include <iostream>
using namespace std;
int n;
int a[1000];
int f(int x) {
    int ret = 0;
    for (; x; x &= x - 1) ret++;
    return ret;
}
int g(int x) { return x & -x; }
int main() {
    cin >> n;
    for (int i = 0; i < n; i++) cin >> a[i];
    for (int i = 0; i < n; i++)
        cout << f(a[i]) + g(a[i]) << ' ';
    cout << endl;
    return 0;
}
```

### 第 15 题【阅读程序】（2022 真题）以下代码中，删去 unsigned 关键字，程序行为不变。（ ）
```cpp
#include <iostream>
using namespace std;
int main() {
    unsigned short x, y;
    cin >> x >> y;
    x = (x | x << 2) & 0x33;
    x = (x | x << 1) & 0x55;
    y = (y | y << 2) & 0x33;
    y = (y | y << 1) & 0x55;
    unsigned short z = x | y << 1;
    cout << z << endl;
    return 0;
}
```

