每次操作后暴力排序 O(n)，n≤8000 可通过。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, q; cin >> n >> q;
    vector<int> a(n + 1);
    for (int i = 1; i <= n; i++) cin >> a[i];
    while (q--) {
        int op; cin >> op;
        if (op == 1) {
            int x, v; cin >> x >> v;
            a[x] = v;
        } else {
            int x; cin >> x;
            vector<pair<int,int>> b;
            for (int i = 1; i <= n; i++) b.emplace_back(a[i], i);
            sort(b.begin(), b.end());
            for (int i = 0; i < n; i++)
                if (b[i].second == x) { cout << i + 1 << "\n"; break; }
        }
    }
    return 0;
}
```

先算龙虎气势，再枚举兵营加s2取最小差。

```cpp
#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
int main() {
    int n; cin >> n;
    vector<ll> c(n + 1);
    for (int i = 1; i <= n; i++) cin >> c[i];
    int m, p1, s1, s2; cin >> m >> p1 >> s1 >> s2;
    c[p1] += s1;
    ll dr = 0, hu = 0;
    for (int i = 1; i < m; i++) dr += c[i] * (m - i);
    for (int i = m + 1; i <= n; i++) hu += c[i] * (i - m);
    ll best = LLONG_MAX;
    int ans = 1;
    for (int i = 1; i <= n; i++) {
        if (i == m) continue;
        ll d2 = dr, h2 = hu;
        if (i < m) d2 += s2 * (m - i);
        else h2 += s2 * (i - m);
        ll diff = abs(d2 - h2);
        if (diff < best) { best = diff; ans = i; }
    }
    cout << ans << endl;
    return 0;
}
```

方向数组辅助模拟，vis记录访问。

```cpp
#include <bits/stdc++.h>
using namespace std;
int dx[4] = {0, 1, 0, -1};
int dy[4] = {1, 0, -1, 0};
int main() {
    int T; cin >> T;
    while (T--) {
        int n, m, k; cin >> n >> m >> k;
        int x, y, d; cin >> x >> y >> d; x--; y--;
        vector<string> g(n);
        for (int i = 0; i < n; i++) cin >> g[i];
        vector<vector<bool>> vis(n, vector<bool>(m, false));
        vis[x][y] = true;
        while (k--) {
            int nx = x + dx[d], ny = y + dy[d];
            if (nx >= 0 && nx < n && ny >= 0 && ny < m && g[nx][ny] == '.') {
                x = nx; y = ny;
            } else d = (d + 1) % 4;
            vis[x][y] = true;
        }
        int ans = 0;
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m; j++)
                if (vis[i][j]) ans++;
        cout << ans << endl;
    }
    return 0;
}
```

降序排序后，列=排名/n+1，行依列奇偶定方向。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, m; cin >> n >> m;
    int tot = n * m;
    vector<pair<int,int>> a(tot);
    for (int i = 0; i < tot; i++) { cin >> a[i].first; a[i].second = i; }
    sort(a.rbegin(), a.rend());
    for (int i = 0; i < tot; i++) {
        if (a[i].second == 0) {
            int col = i / n + 1;
            int row = (col % 2) ? (i % n + 1) : (n - i % n);
            cout << col << " " << row << endl;
            return 0;
        }
    }
}
```
